def get_quiz_by_name(name):
    quiz = quiz_express.get(name)
    if quiz:
        return quiz
    
    quiz = quiz_maison.get(name)
    if quiz:
        return quiz
    
    quiz = quiz_patronus.get(name)
    if quiz:
        return quiz
    
    quiz = quiz_alignement.get(name)
    if quiz:
        return quiz
    
    quiz = quiz_matiere.get(name)
    if quiz:
        return quiz
